import { useState, useRef, useEffect, useCallback } from 'react';

const useResizablePanels = () => {
  const [sidebarWidth, setSidebarWidth] = useState(280);
  const [editorWidth, setEditorWidth] = useState(50); // percentage
  const [isResizing, setIsResizing] = useState(null);
  const containerRef = useRef(null);
  const startX = useRef(0);
  const startWidth = useRef(0);
  const startEditorWidth = useRef(0);

  const handleMouseDown = useCallback((e, panel) => {
    e.preventDefault();
    setIsResizing(panel);
    startX.current = e.clientX;

    if (panel === 'sidebar') {
      startWidth.current = sidebarWidth;
    } else if (panel === 'editor') {
      startEditorWidth.current = editorWidth;
    }
  }, [sidebarWidth, editorWidth]);

  const handleMouseMove = useCallback((e) => {
    if (!isResizing) return;

    const deltaX = e.clientX - startX.current;

    if (isResizing === 'sidebar') {
      const newWidth = Math.max(200, Math.min(500, startWidth.current + deltaX));
      setSidebarWidth(newWidth);
    } else if (isResizing === 'editor') {
      if (containerRef.current) {
        const containerWidth = containerRef.current.offsetWidth;
        const sidebarWidthPx = sidebarWidth;
        const availableWidth = containerWidth - sidebarWidthPx;
        const newEditorWidth = Math.max(30, Math.min(70,
          (startEditorWidth.current * availableWidth + deltaX) / availableWidth * 100
        ));
        setEditorWidth(newEditorWidth);
      }
    }
  }, [isResizing, sidebarWidth]);

  const handleMouseUp = useCallback(() => {
    setIsResizing(null);
  }, []);

  useEffect(() => {
    if (isResizing) {
      document.addEventListener('mousemove', handleMouseMove);
      document.addEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'col-resize';
      document.body.style.userSelect = 'none';

      return () => {
        document.removeEventListener('mousemove', handleMouseMove);
        document.removeEventListener('mouseup', handleMouseUp);
        document.body.style.cursor = '';
        document.body.style.userSelect = '';
      };
    }
  }, [isResizing, handleMouseMove, handleMouseUp]);

  return {
    sidebarWidth,
    editorWidth,
    setSidebarWidth,
    setEditorWidth,
    isResizing,
    handleMouseDown,
    containerRef,
    previewWidth: 100 - editorWidth
  };
};

export default useResizablePanels;
